public string GerarPromptLLM(Lead lead, List<MensagemWhatsApp> mensagens)
    {
        var historicoLinhas = mensagens
            .Where(m => m.Tipo == TipoMensagem.Texto && !string.IsNullOrWhiteSpace(m.Conteudo))
            .Select(m => $"[{m.EnviadaEm:yyyy-MM-dd HH:mm}] {m.Conteudo}")
            .ToList();

        var historico = historicoLinhas.Count > 0
            ? string.Join(Environment.NewLine, historicoLinhas)
            : "(sem mensagens de texto)";

        var nome = lead.NomeReal ?? lead.NomeWhatsApp;

        return $$"""
Você é um assistente do Espaço Lua Cheia, um local de eventos em Rio das Ostras, RJ.

Contexto do negócio:
- Locação de espaço para festas e casamentos
- Capacidade: até 200 pessoas
- Necessita visita para orçamento presencial
- Suítes disponíveis para pernoite

Histórico de mensagens do contato {{nome}} (celular: {{lead.Celular}}):
{{historico}}

Com base nessas mensagens, identifique:
1. Tipo de evento (festa/casamento)
2. Número aproximado de convidados
3. Data ou período desejado
4. Se há interesse em visita

Sugira ações no formato JSON:
{"acoes": [
  {"tipo": "AgendarVisita", "dataDesejada": "YYYY-MM-DD ou null"},
  {"tipo": "CriarOrcamento", "tipoEvento": "Festa", "quantidadePessoas": 0}
]}
""";
    }
