using System.Text.Json;
using EspacoLuaCheia.Web.Features.Leads.Integrations;
using EspacoLuaCheia.Web.Features.Leads.Integrations.Dtos;
using EspacoLuaCheia.Web.Features.Leads.Services.Dtos;

public async Task<List<EvolutionMessageDto>> BuscarMensagens(string remoteJid)
    {
        try
        {
            var items = await evolutionApiClient.FindMessages(remoteJid);

            var result = new List<EvolutionMessageDto>();
            foreach (var item in items)
            {
                var msg = ParseMessage(item);
                if (msg is not null)
                    result.Add(msg);
            }

            return result;
        }
        catch (Exception ex)
        {
            logger.LogError(ex, "Erro ao buscar mensagens do contato {RemoteJid}", remoteJid);
            return [];
        }
    }
