using System.Text.Json;
using EspacoLuaCheia.Web.Features.Leads.Integrations.Dtos;

public async Task<List<FindMessagesRecord>> FindMessages(string remoteJid)
    {
        var client = CreateClient();
        var body = new StringContent(
            JsonSerializer.Serialize(new { where = new { key = new { remoteJid } } }),
            System.Text.Encoding.UTF8, "application/json");
        var response = await client.PostAsync($"/chat/findMessages/{InstanceName}", body);
        response.EnsureSuccessStatusCode();
        var json = await response.Content.ReadAsStringAsync();
        var envelope = JsonSerializer.Deserialize<FindMessagesEnvelope>(json, JsonOptions);
        return envelope?.Messages.Records ?? [];
    }
