using EspacoLuaCheia.Web.Features.Leads.Services.Dtos;

public async Task<(byte[] Dados, string MimeType)> DownloadMidia(string messageId, string mimeTypeHint)
    {
        try
        {
            var response = await evolutionApiClient.GetBase64FromMediaMessage(messageId);

            var base64 = response.Base64 ?? string.Empty;
            var mimeType = response.Mimetype ?? mimeTypeHint;

            if (string.IsNullOrEmpty(base64))
                return ([], mimeTypeHint);

            // Remove prefixo "data:image/jpeg;base64," se presente
            var commaIdx = base64.IndexOf(',');
            if (commaIdx >= 0)
                base64 = base64[(commaIdx + 1)..];

            var dados = Convert.FromBase64String(base64);
            return (dados, mimeType);
        }
        catch (Exception ex)
        {
            logger.LogError(ex, "Erro ao fazer download de mídia via base64");
            return ([], mimeTypeHint);
        }
    }
