using System.Text.Json;
using EspacoLuaCheia.Web.Features.Leads.Integrations;
using EspacoLuaCheia.Web.Features.Leads.Integrations.Dtos;
using EspacoLuaCheia.Web.Features.Leads.Services.Dtos;

private static EvolutionMessageDto? ParseMessage(FindMessagesRecord item)
    {
        var externalId = item.Key.Id;
        var remoteJid = item.Key.RemoteJid;
        var fromMe = item.Key.FromMe;
        var timestamp = item.MessageTimestamp;
        var pushName = item.PushName;

        string? texto = null;
        string? mediaUrl = null;
        string? mimeType = null;
        string? fileName = null;
        string tipoRaw = "unknown";

        if (item.Message is { } message)
        {
            if (TryGetJsonProperty(message, "conversation", out var conv) && conv.ValueKind == JsonValueKind.String)
            {
                texto = conv.GetString();
                tipoRaw = "conversation";
            }
            else if (TryGetJsonProperty(message, "imageMessage", out var imgMsg) && imgMsg.ValueKind != JsonValueKind.Null)
            {
                tipoRaw = "imageMessage";
                mediaUrl = imgMsg.TryGetProperty("url", out var u) ? u.GetString() : null;
                mimeType = imgMsg.TryGetProperty("mimetype", out var mt) ? mt.GetString() : "image/jpeg";
            }
            else if (TryGetJsonProperty(message, "audioMessage", out var audioMsg) && audioMsg.ValueKind != JsonValueKind.Null)
            {
                tipoRaw = "audioMessage";
                mediaUrl = audioMsg.TryGetProperty("url", out var u) ? u.GetString() : null;
                mimeType = audioMsg.TryGetProperty("mimetype", out var mt) ? mt.GetString() : "audio/ogg";
            }
            else if (TryGetJsonProperty(message, "documentMessage", out var docMsg) && docMsg.ValueKind != JsonValueKind.Null)
            {
                tipoRaw = "documentMessage";
                mediaUrl = docMsg.TryGetProperty("url", out var u) ? u.GetString() : null;
                mimeType = docMsg.TryGetProperty("mimetype", out var mt) ? mt.GetString() : "application/octet-stream";
                fileName = docMsg.TryGetProperty("fileName", out var fn) ? fn.GetString() : null;
            }
            else if (TryGetJsonProperty(message, "videoMessage", out var videoMsg) && videoMsg.ValueKind != JsonValueKind.Null)
            {
                tipoRaw = "videoMessage";
                mediaUrl = videoMsg.TryGetProperty("url", out var u) ? u.GetString() : null;
                mimeType = videoMsg.TryGetProperty("mimetype", out var mt) ? mt.GetString() : "video/mp4";
            }
            else if (TryGetJsonProperty(message, "stickerMessage", out var stickerMsg) && stickerMsg.ValueKind != JsonValueKind.Null)
            {
                tipoRaw = "stickerMessage";
                mediaUrl = stickerMsg.TryGetProperty("url", out var u) ? u.GetString() : null;
                mimeType = stickerMsg.TryGetProperty("mimetype", out var mt) ? mt.GetString() : "image/webp";
            }
        }

        if (string.IsNullOrEmpty(externalId))
            return null;

        return new EvolutionMessageDto(externalId, remoteJid, fromMe, timestamp, pushName, texto, mediaUrl, mimeType, fileName, tipoRaw);
    }
