```csharp
// File: Features/Leads/Services/FindWhatsappContacts.cs
// Namespace: EspacoLuaCheia.Web.Features.Leads.Services
// Class: FindWhatsappContacts
using System.Text.Json;
using EspacoLuaCheia.Web.Features.Leads.Integrations;
using EspacoLuaCheia.Web.Features.Leads.Services.Dtos;

public async Task<List<EvolutionChatDto>> Execute()
    {
        try
        {
            // 1) findChats — pega remoteJids que têm mensagens (inclui @lid)
            var chats = await evolutionApiClient.FindChats();

            var chatJids = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            var lidToPushName = new Dictionary<string, string?>(StringComparer.OrdinalIgnoreCase);

            foreach (var chat in chats)
            {
                var jid = chat.RemoteJid;
                if (string.IsNullOrEmpty(jid) || jid.Contains("@g.us") || jid == "status@broadcast")
                    continue;

                chatJids.Add(jid);

                if (jid.Contains("@lid"))
                {
                    var pn = chat.PushName;
                    if (string.IsNullOrEmpty(pn) && chat.LastMessage is { } lm)
                    {
                        if (!lm.Key.FromMe)
                            pn = lm.PushName;
                    }
                    lidToPushName[jid] = pn;
                }
            }

            // Resolver pushName de @lid que ficaram sem nome — buscar nas mensagens recebidas
            foreach (var lidJid in lidToPushName.Where(kv => string.IsNullOrEmpty(kv.Value)).Select(kv => kv.Key).ToList())
            {
                try
                {
                    var msgs = await findWhatsappMessages.BuscarMensagens(lidJid);
                    var pnFromMsg = msgs.FirstOrDefault(m => !m.FromMe && !string.IsNullOrWhiteSpace(m.PushName))?.PushName;
                    if (!string.IsNullOrEmpty(pnFromMsg))
                        lidToPushName[lidJid] = pnFromMsg;
                }
                catch (Exception ex)
                {
                    logger.LogWarning(ex, "Não conseguiu resolver pushName para {LidJid}", lidJid);
                }
            }

            logger.LogInformation("findChats: {Total} chats, {Lid} @lid, {Whatsapp} @s.whatsapp.net",
                chatJids.Count,
                chatJids.Count(j => j.Contains("@lid")),
                chatJids.Count(j => j.Contains("@s.whatsapp.net")));

            // 2) findContacts — pega contatos com número de telefone (@s.whatsapp.net)
            var contacts = await evolutionApiClient.FindContacts();

            var contactsByJid = new Dictionary<string, string?>(StringComparer.OrdinalIgnoreCase);
            foreach (var c in contacts)
            {
                if (!c.RemoteJid.Contains("@s.whatsapp.net") || c.RemoteJid == "0@s.whatsapp.net")
                    continue;
                contactsByJid.TryAdd(c.RemoteJid, c.PushName);
            }

            logger.LogInformation("findContacts: {Count} contatos com número de telefone", contactsByJid.Count);

            // 3) Resultado: contatos que aparecem em chats (com mensagens)
            var result = new List<EvolutionChatDto>();

            // 3a) Chats @s.whatsapp.net que estão em findChats
            foreach (var jid in chatJids.Where(j => j.Contains("@s.whatsapp.net") && j != "0@s.whatsapp.net"))
            {
                contactsByJid.TryGetValue(jid, out var pushName);
                var celular = new string(jid.TakeWhile(c => c != '@').Where(char.IsDigit).ToArray());
                result.Add(new EvolutionChatDto(jid, celular, pushName, 0));
            }

            // 3b) Chats @lid: sempre manter o @lid como RemoteJid (mensagens estão indexadas por ele)
            // Tentar resolver o celular via pushName match com findContacts
            var lidResolved = 0;
            var lidUnresolved = 0;
            foreach (var (lidJid, lidName) in lidToPushName)
            {
                string? celularResolvido = null;

                if (!string.IsNullOrWhiteSpace(lidName))
                {
                    var match = contactsByJid
                        .FirstOrDefault(c => string.Equals(c.Value, lidName, StringComparison.OrdinalIgnoreCase)
                                            && !result.Any(r => r.Celular == new string(c.Key.TakeWhile(ch => ch != '@').Where(char.IsDigit).ToArray())));

                    if (!string.IsNullOrEmpty(match.Key))
                    {
                        celularResolvido = new string(match.Key.TakeWhile(c => c != '@').Where(char.IsDigit).ToArray());
                        lidResolved++;
                    }
                    else
                    {
                        lidUnresolved++;
                    }
                }
                else
                {
                    lidUnresolved++;
                }

                result.Add(new EvolutionChatDto(lidJid, celularResolvido, lidName, 0));
            }

            logger.LogInformation("Resultado: {Direct} diretos + {Resolved} @lid resolvidos + {Unresolved} @lid sem número = {Total} contatos importáveis.",
                result.Count - lidResolved - lidUnresolved, lidResolved, lidUnresolved, result.Count);

            return result;
        }
        catch (Exception ex)
        {
            logger.LogError(ex, "Erro ao buscar contatos da Evolution API");
            return [];
        }
    }
