[Trecho 2] Features/Leads/Services/WhatsAppWebhookHandler.cs:19-167  (símbolo: WhatsAppWebhookHandler.ProcessarAsync, tipo: method)
```csharp
// File: Features/Leads/Services/WhatsAppWebhookHandler.cs
// Namespace: EspacoLuaCheia.Web.Features.Leads.Services
// Class: WhatsAppWebhookHandler
using System.Text.Json;
using EspacoLuaCheia.Web.Data;
using EspacoLuaCheia.Web.Features.Leads.Entities;
using EspacoLuaCheia.Web.Features.Leads.Enums;
using EspacoLuaCheia.Web.Features.Leads.Specifications;
using Microsoft.AspNetCore.Hosting;
using Microsoft.EntityFrameworkCore;

public async Task ProcessarAsync(string payloadJson)
    {
        JsonElement root;
        try
        {
            root = JsonSerializer.Deserialize<JsonElement>(payloadJson, JsonOptions);
        }
        catch (Exception ex)
        {
            logger.LogWarning(ex, "Payload do webhook inválido");
            return;
        }

        if (!root.TryGetProperty("event", out var eventProp) || eventProp.GetString() != "messages.upsert")
            return;

        if (!root.TryGetProperty("data", out var data))
            return;

        if (!data.TryGetProperty("key", out var key))
            return;

        var fromMe = key.TryGetProperty("fromMe", out var fmProp) && fmProp.GetBoolean();
        if (fromMe)
            return;

        var remoteJid = key.TryGetProperty("remoteJid", out var jidProp) ? jidProp.GetString() ?? string.Empty : string.Empty;
        if (string.IsNullOrEmpty(remoteJid))
            return;

        var externalId = key.TryGetProperty("id", out var idProp) ? idProp.GetString() ?? string.Empty : string.Empty;
        if (string.IsNullOrEmpty(externalId))
            return;

        var celular = NormalizarCelular(remoteJid);
        if (string.IsNullOrEmpty(celular))
            return;

        var celularesBloqueados = await db.CelularesBloqueados
            .Select(c => c.Celular)
            .ToListAsync();

        var naoBloqueadoSpec = new CelularNaoBloqueadoSpec(celularesBloqueados);
        if (!naoBloqueadoSpec.IsSatisfiedBy(celular))
        {
            logger.LogInformation("Celular bloqueado ignorado: {Celular}", celular);
            return;
        }

        var pushName = data.TryGetProperty("pushName", out var pnProp) ? pnProp.GetString() : null;

        long timestamp = 0;
        if (data.TryGetProperty("messageTimestamp", out var tsProp))
        {
            if (tsProp.ValueKind == JsonValueKind.Number)
                timestamp = tsProp.GetInt64();
            else if (tsProp.ValueKind == JsonValueKind.String && long.TryParse(tsProp.GetString(), out var parsed))
                timestamp = parsed;
        }

        var agora = DateTime.UtcNow;
        var enviadaEm = timestamp > 0 ? DateTimeOffset.FromUnixTimeSeconds(timestamp).UtcDateTime : agora;

        var lead = await db.Leads.FirstOrDefaultAsync(l => l.Celular == celular);

        if (lead is null)
        {
            lead = new Lead
            {
                Celular = celular,
                NomeWhatsApp = pushName ?? celular,
                Status = StatusLead.Novo,
                UltimaMensagemEm = agora,
                CriadoEm = agora,
                AtualizadoEm = agora
            };
            db.Leads.Add(lead);
            await db.SaveChangesAsync();
        }
        else
        {
            lead.UltimaMensagemEm = agora;
            lead.AtualizadoEm = agora;
            if (!string.IsNullOrWhiteSpace(pushName))
                lead.NomeWhatsApp = pushName;
            await db.SaveChangesAsync();
        }

        var externalIdsExistentes = await db.MensagensWhatsApp
            .Where(m => m.LeadId == lead.Id)
            .Select(m => m.ExternalId)
            .ToListAsync();

        var naoDuplicadaSpec = new MensagemNaoDuplicadaSpec(externalIdsExistentes);
        if (!naoDuplicadaSpec.IsSatisfiedBy(externalId))
        {
            logger.LogInformation("Mensagem duplicada ignorada: ExternalId={ExternalId}", externalId);
            return;
        }

        var (tipo, texto, mimeType, fileName) = ExtrairConteudo(data);

        string? arquivoUrlLocal = null;
        string? arquivoNome = fileName;
        string? arquivoMimeType = mimeType;

        var ehMidia = tipo is TipoMensagem.Imagem or TipoMensagem.Audio or TipoMensagem.Documento or TipoMensagem.Video or TipoMensagem.Sticker;
        if (ehMidia)
        {
            try
            {
                // v2: download via message key ID
                var (dados, mimeTypeRetornado) = await findWhatsappMessages.DownloadMidia(externalId, mimeType ?? "application/octet-stream");
                if (dados.Length > 0)
                {
                    var ext = ObterExtensao(mimeTypeRetornado, externalId);
                    var dirPath = Path.Combine(env.WebRootPath, "uploads", "whatsapp", lead.Id.ToString());
                    Directory.CreateDirectory(dirPath);
                    var nomeArquivo = $"{externalId}{ext}";
                    var caminhoFisico = Path.Combine(dirPath, nomeArquivo);
                    await File.WriteAllBytesAsync(caminhoFisico, dados);
                    arquivoUrlLocal = $"/uploads/whatsapp/{lead.Id}/{nomeArquivo}";
                    arquivoMimeType = mimeTypeRetornado;
                    if (string.IsNullOrEmpty(arquivoNome))
                        arquivoNome = nomeArquivo;
                }
            }
            catch (Exception ex)
            {
                logger.LogError(ex, "Erro ao fazer download de mídia para mensagem {ExternalId}", externalId);
            }
        }

        var mensagem = new MensagemWhatsApp
        {
            LeadId = lead.Id,
            ExternalId = externalId,
            Tipo = tipo,
            Conteudo = texto,
            ArquivoUrl = arquivoUrlLocal,
            ArquivoNome = arquivoNome,
            ArquivoMimeType = arquivoMimeType,
            EnviadaEm = enviadaEm,
            CriadoEm = agora
        };

        db.MensagensWhatsApp.Add(mensagem);
        await db.SaveChangesAsync();
    }
