```csharp
// File: Features/Leads/Services/ImportacaoHistoricoService.cs
// Namespace: EspacoLuaCheia.Web.Features.Leads.Services
// Class: ImportacaoHistoricoService
using EspacoLuaCheia.Web.Data;
using EspacoLuaCheia.Web.Features.Leads.Dtos;
using EspacoLuaCheia.Web.Features.Leads.Services.Dtos;
using EspacoLuaCheia.Web.Features.Leads.Entities;
using EspacoLuaCheia.Web.Features.Leads.Enums;
using EspacoLuaCheia.Web.Features.Leads.Specifications;
using Microsoft.EntityFrameworkCore;

public async Task<ResultadoImportacao> Importar(List<string> remoteJidsParaImportar)
    {
        var leadsCriados = 0;
        var leadsAtualizados = 0;
        var mensagensImportadas = 0;
        var mensagensPuladas = 0;
        var bloqueadosIgnorados = 0;

        var celularesBloqueados = await db.CelularesBloqueados
            .Select(c => c.Celular)
            .ToListAsync();

        var naoBloqueadoSpec = new CelularNaoBloqueadoSpec(celularesBloqueados);

        foreach (var remoteJid in remoteJidsParaImportar)
        {
            if (string.IsNullOrEmpty(remoteJid))
                continue;

            var ehLid = remoteJid.Contains("@lid");
            var celular = ehLid ? null : NormalizarCelular(remoteJid);

            if (!ehLid && string.IsNullOrEmpty(celular))
                continue;

            // Para @lid, usar o próprio lid como identificador temporário
            var celularOuLid = celular ?? NormalizarLid(remoteJid);

            if (!ehLid && !naoBloqueadoSpec.IsSatisfiedBy(celularOuLid))
            {
                bloqueadosIgnorados++;
                continue;
            }

            var agora = DateTime.UtcNow;

            var lead = await db.Leads.FirstOrDefaultAsync(l => l.Celular == celularOuLid);
            if (lead is null)
            {
                lead = new Lead
                {
                    Celular = celularOuLid,
                    NomeWhatsApp = celularOuLid,
                    Status = StatusLead.Novo,
                    UltimaMensagemEm = agora,
                    CriadoEm = agora,
                    AtualizadoEm = agora
                };
                db.Leads.Add(lead);
                await db.SaveChangesAsync();
                leadsCriados++;
            }
            else
            {
                leadsAtualizados++;
            }

            var mensagensApi = await findWhatsappMessages.BuscarMensagens(remoteJid);

            var externalIdsExistentes = await db.MensagensWhatsApp
                .Where(m => m.LeadId == lead.Id)
                .Select(m => m.ExternalId)
                .ToListAsync();

            var naoDuplicadaSpec = new MensagemNaoDuplicadaSpec(externalIdsExistentes);

            foreach (var msg in mensagensApi)
            {
                if (msg.FromMe)
                    continue;

                if (!naoDuplicadaSpec.IsSatisfiedBy(msg.ExternalId))
                {
                    mensagensPuladas++;
                    continue;
                }

                var tipo = msg.TipoRaw switch
                {
                    "conversation" => TipoMensagem.Texto,
                    "imageMessage" => TipoMensagem.Imagem,
                    "audioMessage" => TipoMensagem.Audio,
                    "documentMessage" => TipoMensagem.Documento,
                    "videoMessage" => TipoMensagem.Video,
                    "stickerMessage" => TipoMensagem.Sticker,
                    _ => TipoMensagem.Desconhecido
                };

                var enviadaEm = msg.Timestamp > 0
                    ? DateTimeOffset.FromUnixTimeSeconds(msg.Timestamp).UtcDateTime
                    : agora;

                string? arquivoUrlLocal = null;
                string? arquivoNome = msg.FileName;
                string? arquivoMimeType = msg.MimeType;

                var ehMidia = tipo is TipoMensagem.Imagem or TipoMensagem.Audio or TipoMensagem.Documento or TipoMensagem.Video or TipoMensagem.Sticker;
                if (ehMidia)
                {
                    try
                    {
                        // v2: download via message key ID
                        var (dados, mimeTypeRetornado) = await findWhatsappMessages.DownloadMidia(
                            msg.ExternalId, msg.MimeType ?? "application/octet-stream");

                        if (dados.Length > 0)
                        {
                            var ext = ObterExtensao(mimeTypeRetornado, msg.ExternalId);
                            var dirPath = Path.Combine(env.WebRootPath, "uploads", "whatsapp", lead.Id.ToString());
                            Directory.CreateDirectory(dirPath);
                            var nomeArquivo = $"{msg.ExternalId}{ext}";
                            var caminhoFisico = Path.Combine(dirPath, nomeArquivo);
                            await File.WriteAllBytesAsync(caminhoFisico, dados);
                            arquivoUrlLocal = $"/uploads/whatsapp/{lead.Id}/{nomeArquivo}";
                            arquivoMimeType = mimeTypeRetornado;
                            if (string.IsNullOrEmpty(arquivoNome))
                                arquivoNome = nomeArquivo;
                        }
                    }
                    catch (Exception ex)
                    {
                        logger.LogError(ex, "Erro ao fazer download de mídia para mensagem {ExternalId}", msg.ExternalId);
                    }
                }

                var mensagem = new MensagemWhatsApp
                {
                    LeadId = lead.Id,
                    ExternalId = msg.ExternalId,
                    Tipo = tipo,
                    Conteudo = msg.Texto,
                    ArquivoUrl = arquivoUrlLocal,
                    ArquivoNome = arquivoNome,
                    ArquivoMimeType = arquivoMimeType,
                    EnviadaEm = enviadaEm,
                    CriadoEm = agora
                };

                db.MensagensWhatsApp.Add(mensagem);
                externalIdsExistentes.Add(msg.ExternalId);
                mensagensImportadas++;
            }

            await db.SaveChangesAsync();

            if (lead.NomeWhatsApp == celularOuLid)
            {
                var primeiraComNome = mensagensApi.FirstOrDefault(m => !m.FromMe && !string.IsNullOrWhiteSpace(m.PushName));
                if (primeiraComNome?.PushName is not null)
                {
                    lead.NomeWhatsApp = primeiraComNome.PushName;
                    lead.AtualizadoEm = agora;
                    await db.SaveChangesAsync();
                }
            }
        }

        return new ResultadoImportacao(leadsCriados, leadsAtualizados, mensagensImportadas, mensagensPuladas, bloqueadosIgnorados);
    }
