```csharp
// File: Features/ChatAI/Services/ChatAIService.cs
// Namespace: EspacoLuaCheia.Web.Features.ChatAI.Services
// Class: ChatAIService
using System.Text.Json;
using EspacoLuaCheia.Web.Data;
using EspacoLuaCheia.Web.Features.ChatAI.Commands;
using EspacoLuaCheia.Web.Features.ChatAI.Dtos;
using EspacoLuaCheia.Web.Features.ChatAI.Entities;
using EspacoLuaCheia.Web.Features.ChatAI.Enums;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Configuration;

private static List<object> ConverterHistoricoParaOpenAi(
        List<MensagemChat> historico,
        string? toolCallId = null,
        string? nomeToolParaResult = null)
    {
        var messages = new List<object>();

        foreach (var m in historico)
        {
            switch (m.Remetente)
            {
                case RemetenteChat.Usuario:
                    messages.Add(new { role = "user", content = m.Conteudo });
                    break;

                case RemetenteChat.Assistente when !string.IsNullOrEmpty(m.ToolCallJson):
                    // Mensagem de assistente com tool_call — reconstruir estrutura OpenAI
                    try
                    {
                        var toolCallsArray = JsonSerializer.Deserialize<JsonElement>(m.ToolCallJson);
                        messages.Add(new
                        {
                            role = "assistant",
                            content = (string?)null,
                            tool_calls = toolCallsArray
                        });
                    }
                    catch
                    {
                        // Se falhar parse, omitir mensagem corrompida
                    }
                    break;

                case RemetenteChat.Assistente:
                    messages.Add(new { role = "assistant", content = m.Conteudo });
                    break;

                case RemetenteChat.Sistema when !string.IsNullOrEmpty(m.ToolResultJson) &&
                                               toolCallId is not null &&
                                               nomeToolParaResult is not null:
                    // Tool result — apenas para a mensagem mais recente passada via parâmetro
                    messages.Add(new
                    {
                        role = "tool",
                        tool_call_id = toolCallId,
                        name = nomeToolParaResult,
                        content = m.Conteudo
                    });
                    break;

                case RemetenteChat.Sistema:
                    // Mensagens de sistema anteriores não são enviadas ao modelo
                    break;
            }
        }

        return messages;
    }
