// -------------------------------------------------------------------------
    // Iniciar uma nova sessão com o primeiro input do usuário
    // -------------------------------------------------------------------------
    public async Task<(SessaoChat Sessao, MensagemChatDto Resposta)> IniciarSessaoAsync(
        string textoUsuario,
        CancellationToken ct = default)
    {
        var titulo = textoUsuario.Length > 80
            ? textoUsuario[..80]
            : textoUsuario;

        var agora = DateTime.UtcNow;
        var sessao = new SessaoChat
        {
            TituloPreview = titulo,
            CriadoEm = agora,
            AtualizadoEm = agora
        };
        db.SessoesChatAI.Add(sessao);
        await db.SaveChangesAsync(ct);

        var resposta = await ProcessarMensagemAsync(sessao.Id, textoUsuario, ct);
        return (sessao, resposta);
    }
