private static bool TryGetString(JsonElement el, string prop, out string value)
    {
        if (el.TryGetProperty(prop, out var propEl) &&
            propEl.ValueKind == JsonValueKind.String &&
            !string.IsNullOrWhiteSpace(propEl.GetString()))
        {
            value = propEl.GetString()!;
            return true;
        }
        value = string.Empty;
        return false;
    }
